package src.org.apache.nutch.scoring.webgraph;

public static class AnalyzerReducer extends Reducer < Text , ObjectWritable , Text , Node > { private Configuration conf ; private float dampingFactor = 0.85f ; private float rankOne = 0.0f ; private int itNum = 0 ; private boolean limitPages = true ; private boolean limitDomains = true ; @ Override public void setup ( Reducer < Text , ObjectWritable , Text , Node > . Context context ) { conf = context . getConfiguration ( ) ; dampingFactor = conf . getFloat ( "link.analyze.damping.factor" , 0.85f ) ; rankOne = conf . getFloat ( "link.analyze.rank.one" , 0.0f ) ; itNum = conf . getInt ( "link.analyze.iteration" , 0 ) ; limitPages = conf . getBoolean ( "link.ignore.limit.page" , true ) ; limitDomains = conf . getBoolean ( "link.ignore.limit.domain" , true ) ; } @ Override public void reduce ( Text key , Iterable < ObjectWritable > values , Context context ) throws IOException , InterruptedException { String url = key . toString ( ) ; Set < String > domains = new HashSet < > ( ) ; Set < String > pages = new HashSet < > ( ) ; Node node = null ; int numInlinks = 0 ; float totalInlinkScore = rankOne ; for ( ObjectWritable next : values ) { Object value = next . get ( ) ; if ( value instanceof Node ) { node = ( Node ) value ; } else if ( value instanceof LinkDatum ) { LinkDatum linkDatum = ( LinkDatum ) value ; float scoreFromInlink = linkDatum . getScore ( ) ; String inlinkUrl = linkDatum . getUrl ( ) ; String inLinkDomain = URLUtil . getDomainName ( inlinkUrl ) ; String inLinkPage = URLUtil . getPage ( inlinkUrl ) ; if ( ( limitPages && pages . contains ( inLinkPage ) ) || ( limitDomains && domains . contains ( inLinkDomain ) ) ) { LOG . debug ( url + ": ignoring " + scoreFromInlink + " from " + inlinkUrl + ", duplicate page or domain" ) ; continue ; } numInlinks ++ ; totalInlinkScore += scoreFromInlink ; domains . add ( inLinkDomain ) ; pages . add ( inLinkPage ) ; LOG . debug ( url + ": adding " + scoreFromInlink + " from " + inlinkUrl + ", total: " + totalInlinkScore ) ; } } float linkRankScore = ( 1 - dampingFactor ) + ( dampingFactor * totalInlinkScore ) ; LOG . debug ( url + ": score: " + linkRankScore + " num inlinks: " + numInlinks + " iteration: " + itNum ) ; Node outNode = WritableUtils . clone ( node , conf ) ; outNode . setInlinkScore ( linkRankScore ) ; context . write ( key , outNode ) ; } }